import{_ as t,o as r,c as e,ag as l}from"./chunks/framework.WmBmIPw-.js";const b=JSON.parse('{"title":"精确算法","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/exact/exact-algorithms.md","filePath":"or-opt/exact/exact-algorithms.md","lastUpdated":1777190173000}'),h={name:"or-opt/exact/exact-algorithms.md"};function d(n,a,i,o,s,c){return r(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="精确算法" tabindex="-1">精确算法 <a class="header-anchor" href="#精确算法" aria-label="Permalink to &quot;精确算法&quot;">​</a></h1><p>本页是本站「精确算法」类笔记的总览：说明什么叫精确式方法、本库中各篇目的关系与推荐阅读顺序；每篇的推导与步骤仍以各独立页面为准。</p><hr><h2 id="什么是「精确式」方法" tabindex="-1">什么是「精确式」方法 <a class="header-anchor" href="#什么是「精确式」方法" aria-label="Permalink to &quot;什么是「精确式」方法&quot;">​</a></h2><ul><li><strong>目标</strong>：在可终止的前提下，证明所输出解是（混合）整数规划或相应问题的最优解（或证毕问题不可行/无界）。</li><li><strong>对比</strong>：启发式、元启发式、定界不保证的构造式方法通常不给出最优性证明，而追求快速可行解或好近似。</li><li><strong>代价</strong>：许多精确算法的最坏时间随规模指数增长，工程上常配合预处理、割、定界、并行以缩小实际搜索量。</li></ul><p>在混合整数规划（MIP）语境下，下面笔记中的分支、割、列生成、分解、拉格朗日等，都可作为精确求解管线中的组成模块。</p><hr><h2 id="本库内容结构" tabindex="-1">本库内容结构 <a class="header-anchor" href="#本库内容结构" aria-label="Permalink to &quot;本库内容结构&quot;">​</a></h2><h3 id="_1-以分支定界-bb-为搜索骨架" tabindex="-1">1. 以分支定界（BB）为搜索骨架 <a class="header-anchor" href="#_1-以分支定界-bb-为搜索骨架" aria-label="Permalink to &quot;1. 以分支定界（BB）为搜索骨架&quot;">​</a></h3><ul><li><a href="./branch-and-bound.html">分支定界</a>：用松弛（如 LP）给上/下界，在变量上分支成子问题，剪枝不能改进全局界的节点。是整数规划最经典搜索范式之一。</li><li><a href="./branch-and-cut.html">分支切割</a>：在 BB 节点上加入有效不等式（割），缩小松弛的可行域、收紧界，常显著减少树规模。</li><li><a href="./branch-and-price.html">分支定价</a>：变量极多、难以全部列于模型时，在节点上用列生成按需加列，与 BB 结合。</li><li><a href="./branch-price-and-cut.html">分支定价切割</a>：在分支定价各节点上再叠加割平面，是多种技术的组合形态。</li></ul><p><strong>关系速记</strong>：都是「树搜索 + 松弛定界」；在 BB 上依次叠加割、列或二者，以应对不同结构难点。</p><h3 id="_2-分解与主–子问题结构" tabindex="-1">2. 分解与主–子问题结构 <a class="header-anchor" href="#_2-分解与主–子问题结构" aria-label="Permalink to &quot;2. 分解与主–子问题结构&quot;">​</a></h3><ul><li><a href="./dantzig-wolfe.html">Dantzig–Wolfe 分解</a>：利用块角结构，将大问题写成主问题 + 子问题，常驱动列生成实现。</li><li><a href="./benders.html">Benders 分解</a>：将决策分阶段，用 Benders 割迭代收紧，适合随机规划、多阶段 MIP 等。</li><li><a href="./column-generation.html">列生成</a>：大规模线性规划中按约简费用生成列，亦是分支定价的 LP 子问题核心。</li></ul><p><strong>关系速记</strong>：DW / Benders 是模型层的分解；列生成是算法层在 LP 上的一种求解技术，常与上述分解或分支配套。</p><h3 id="_3-对偶与松弛" tabindex="-1">3. 对偶与松弛 <a class="header-anchor" href="#_3-对偶与松弛" aria-label="Permalink to &quot;3. 对偶与松弛&quot;">​</a></h3><ul><li><a href="./lagrangian.html">拉格朗日松弛</a>：将难约束乘子化移入目标，得可分解子问题；通过对偶/次梯度等更新乘子。可用于界、分支定界中的界或设计启发，与精确算法常结合使用。</li></ul><hr><h2 id="各篇目一览" tabindex="-1">各篇目一览 <a class="header-anchor" href="#各篇目一览" aria-label="Permalink to &quot;各篇目一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>篇目</th><th>一句话</th></tr></thead><tbody><tr><td><a href="./branch-and-bound.html">分支定界</a></td><td>整数规划经典树搜索，松弛定界、分支、剪枝</td></tr><tr><td><a href="./branch-and-cut.html">分支切割</a></td><td>BB + 有效不等式（割）</td></tr><tr><td><a href="./column-generation.html">列生成</a></td><td>大规模 LP，按需加列</td></tr><tr><td><a href="./branch-and-price.html">分支定价</a></td><td>BB + 列生成</td></tr><tr><td><a href="./branch-price-and-cut.html">分支定价切割</a></td><td>分支定价 + 割</td></tr><tr><td><a href="./dantzig-wolfe.html">Dantzig–Wolfe 分解</a></td><td>块角结构，主问题–子问题、常见列生成就位</td></tr><tr><td><a href="./benders.html">Benders 分解</a></td><td>Benders 割迭代，多阶段/分解结构</td></tr><tr><td><a href="./lagrangian.html">拉格朗日松弛</a></td><td>难约束乘子化，可分解、给界、调乘子</td></tr></tbody></table><hr><h2 id="建议阅读顺序-可选" tabindex="-1">建议阅读顺序（可选） <a class="header-anchor" href="#建议阅读顺序-可选" aria-label="Permalink to &quot;建议阅读顺序（可选）&quot;">​</a></h2><ol><li>若关心理论主线：分支定界 → 分支切割 → 需要大规模变量时看列生成 / 分支定价 → 再视需要看 BPC、DW、Benders。</li><li>若更关心界与可分解子问题：拉格朗日可较早阅读，并回到分支定界/定价语境下理解其用法。</li><li>各篇中的算法框、数学形式与实现细节，均以对应独立页面为准。</li></ol><hr><p>图论上的最短路（Dijkstra、Bellman-Ford 等）属于另一导航分组「<a href="./../graph/dijkstra.html">图算法</a>」，其多数情形同样是在声明的模型上精确求解到最优；与 MIP 精确算法在应用上可并列参考。</p>',24)])])}const f=t(h,[["render",d]]);export{b as __pageData,f as default};
